        .op-opt-btn { flex: 1; padding: 8px; border: 1px solid var(--border); background: var(--card-bg); color: var(--text-muted); font-size: 11px; border-radius: 6px; cursor: pointer; display: flex; align-items: center; justify-content: center; gap: 6px; }
        .op-opt-btn:hover { background: #222; color: white; }

        /* VIEWERS (Full Screen Overlays) */
        .viewer-overlay {
            position: fixed; top: 0; left: 0; width: 100%; height: 100%;
