            overflow-x: auto; scrollbar-width: none;
            -webkit-overflow-scrolling: touch;
        }
        .viewer-header::-webkit-scrollbar { display: none; }
        .viewer-header > * { flex-shrink: 0; }
        .viewer-title { font-weight: 600; font-size: 14px; font-family: 'JetBrains Mono', monospace; }
        #ace-container { flex: 1; width: 100%; position: relative; }

        /* PREVIEW TAB */
        .browser-toolbar {
            display: flex; gap: 8px; padding: 8px 12px; background: #1a1a1c; border: 1px solid var(--border);
            border-radius: 12px; margin-bottom: 12px; align-items: center;
        }
        .url-bar {
            flex: 1; background: #0a0a0a; border: 1px solid #333; color: #eee; padding: 6px 12px;
