            .ef-list { flex-direction: row; overflow-x: auto; overflow-y: hidden; white-space: nowrap; padding: 12px; height: 60px; }
            .ef-list-item { min-width: 120px; flex-shrink: 0; }
            .ef-stage { padding: 12px !important; }
            .ef-controls { padding: 12px !important; flex-direction: column; align-items: stretch !important; gap: 10px; }
        }

        /* CODE BLOCKS IN MODALS */
        .code-block-wrapper { position: relative; margin-bottom: 12px; }
        .code-label { font-size: 10px; color: var(--text-muted); margin-bottom: 4px; display: block; text-transform: uppercase; }
        .code-pre { background: #050505; border: 1px solid var(--border); padding: 12px; border-radius: 8px; overflow-x: auto; font-family: 'JetBrains Mono', monospace; font-size: 11px; margin: 0; white-space: pre-wrap; color: #ccc; }
        .code-copy { position: absolute; top: 22px; right: 8px; background: rgba(255,255,255,0.1); border: none; color: #fff; padding: 2px 6px; border-radius: 4px; font-size: 10px; cursor: pointer; }
        .diff-remove { background: rgba(239, 68, 68, 0.1); border-left: 2px solid var(--danger); color: #fca5a5; }
        .diff-add { background: rgba(34, 197, 94, 0.1); border-left: 2px solid var(--prod); color: #86efac; }

        /* MOBILE RESPONSIVE STACKS */
        @media (max-width: 600px) {
            #diff-viewer > div[style*="flex:1; display:flex"] {
                flex-direction: column !important;
