        /* ============================ */
        /*      NEW AI CHAT STYLES      */
        /* ============================ */

        /* Multi-Action FAB Group */
        .fab-group {
            position: fixed; bottom: 100px; right: 20px; z-index: 200;
            display: flex; flex-direction: column; align-items: center; gap: 15px;
            pointer-events: none; /* Allow clicks to pass through empty spaces */
        }
        .fab-main {
            width: 56px; height: 56px; border-radius: 50%;
            background: var(--ai-accent); color: white; border: none;
            box-shadow: 0 4px 20px rgba(217, 70, 239, 0.4);
            cursor: pointer; display: flex; align-items: center; justify-content: center;
            transition: all 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
            pointer-events: auto; /* Re-enable clicks for the button */
        }
        .fab-group.active .fab-main { transform: rotate(135deg); background: #333; box-shadow: none; }

        .fab-sub-container {
            display: flex; flex-direction: column; gap: 10px; align-items: center;
            pointer-events: none; opacity: 0; transform: translateY(20px) scale(0.5);
