            display: flex; gap: 4px; background: #111; padding: 2px; border-radius: 4px; border: 1px solid #333;
        }
        .msg-ai .msg-actions { right: auto; left: 0; }
        .action-mini-btn { 
            background: none; border: none; color: #888; cursor: pointer; padding: 2px 4px; font-size: 10px; 
        }
        .action-mini-btn:hover { color: white; }

        /* Code blocks in chat */
        .msg-ai pre { background: #111; padding: 8px; border-radius: 6px; overflow-x: auto; margin-top: 8px; font-family: 'JetBrains Mono', monospace; font-size: 11px; }

        .chat-input-area {
            padding: 12px; background: #0a0a0a; border-top: 1px solid var(--border);
            display: flex; gap: 8px; padding-bottom: 30px; /* Safe area */
        }
        .chat-input {
            flex: 1; background: #1a1a1c; border: 1px solid #333; color: white;
            padding: 12px 16px; border-radius: 12px; outline: none; font-size: 13px;
            resize: none; height: 42px; max-height: 150px; line-height: 1.4;
            font-family: inherit;
        }
        .chat-input:focus { border-color: var(--ai-accent); }

/* Chat History Styles */
        .chat-history-overlay {
            position: absolute; top: 60px; left: 0; width: 100%; height: calc(100% - 60px);
            background: #151517; z-index: 10; display: none;
