    let chatUseSystemPrompt = false;
    let activeCustomPrompt = null;
    let customPrompts = JSON.parse(localStorage.getItem('conduit_custom_prompts') || '[]');
    let filters = {
        patcher: { time: 'all', files: [], categories: ['patch', 'sql', 'ai', 'system'] },
        history: { time: 'all', files: [] },
        cicd: { time: 'all', files: [] }
