    async function executeCreateCron() {
        const job_name = document.getElementById('cron-job-name').value.trim();
        let schedule = document.getElementById('cron-schedule').value.trim();
        const function_slug = document.getElementById('cron-target-slug').value.trim();

        if(!job_name || !schedule || !function_slug) return showGlobalToast("Fill all fields", true);

        // --- HUMAN LANGUAGE TRANSLATOR ---
        if (schedule.toLowerCase() === '30s') {
            schedule = '*/30 * * * * *'; // 6-part cron for seconds
        } else if (!isNaN(schedule)) {
            schedule = `*/${schedule} * * * *`; // Treat plain numbers as minutes
        }

        const isEditing = !!currentEditingJobId;
        showGlobalToast(isEditing ? "Updating..." : "Scheduling...");

        try {
            const action = isEditing ? 'alter_cron_job' : 'create_cron_job';
            const body = isEditing 
                ? apiBody({ action, job_id: currentEditingJobId, schedule, function_slug }) 
                : apiBody({ action, job_name, schedule, function_slug });

            const res = await fetch(CONFIG.funcUrl, {
                method: 'POST', headers: {'Content-Type': 'application/json'},
                body: body
            });
            const data = await res.json();
            if(data.success) {
                showGlobalToast("â " + data.message);
                closeCronManager();
                fetchState(true);
            } else throw new Error(data.error);
        } catch(e) { showGlobalToast(e.message, true); }
    }

