    // --- API & DATA ---
    async function fetchState(force = false, updateTerminal = true, isAppend = false) {
        if(force && !isAppend) {
            document.getElementById('history-container').innerHTML = '<div style="padding:10px; text-align:center;">Syncing...</div>';
            if (updateTerminal) document.getElementById('terminal-list').innerHTML = '<div style="padding:10px; text-align:center; color:#666">Syncing logs...</div>';
        }
        try {
            const res = await fetch(CONFIG.funcUrl, { 
                method: 'POST', headers: {'Content-Type': 'application/json'}, 
                body: apiBody({ 
                    action: 'init', 
                    project_path: CONFIG.projectPath,
                    history_offset: isAppend ? historyOffset : 0,
                    log_offset: isAppend ? logOffset : 0
                }) 
            });
            const data = await res.json();

            const validHistory = (data.history || []).filter(h => h.type !== 'Chat');
            if (isAppend) dbHistory = dbHistory.concat(validHistory);
            else dbHistory = validHistory;

            applyFiltersToHistory();

            const historyBtn = document.getElementById('load-more-history-btn');
            if (historyBtn) {
                if (validHistory.length < 10) historyBtn.style.display = 'none';
                else historyBtn.style.display = 'block';
            }

            if (updateTerminal) {
                const termContainer = document.getElementById('terminal-list');
                if (!isAppend) termContainer.innerHTML = ''; 

                if(data.logs && data.logs.length > 0) {
                    const visibleLogs = data.logs;
                    visibleLogs.forEach(log => {
                        const id = 'term-saved-' + log.id;
                        if (document.getElementById(id)) return; // Avoid duplicates
                        const div = document.createElement('div');
                        div.id = id; div.className = 'log-entry';
                        termContainer.appendChild(div); 
                        updateTerminalCard(id, log.data, log.data.ops, false);
                        const timeEl = div.querySelector('.log-time');
                        if(timeEl) timeEl.innerText = new Date(log.created_at).toLocaleString();
                    });
                    if (visibleLogs.length < 10) document.getElementById('load-more-logs-btn').style.display = 'none';
                    else document.getElementById('load-more-logs-btn').style.display = 'block';
                } else if (!isAppend) {
                    termContainer.innerHTML = '<div style="padding:10px; text-align:center; color:#444; font-size:12px;">No logs.</div>';
                    document.getElementById('load-more-logs-btn').style.display = 'none';
                }
            }
        } catch (e) {
            console.error(e);
            document.getElementById('history-container').innerHTML = `<div style="padding:20px; text-align:center; color:var(--danger);">Failed to sync history: ${e.message}</div>`;
            if (updateTerminal) document.getElementById('terminal-list').innerHTML = `<div style="padding:20px; text-align:center; color:var(--danger);">Log Sync Error.</div>`;
        }
    }

