            if (text.includes('```json') || text.trim().startsWith('[')) {
                 html = html.replace(/<pre><code class="language-json">([\s\S]*?)<\/code><\/pre>/, (match) => {
                     return match + `<button class="btn-dev" style="margin-top:10px; font-size:11px; padding:6px;" onclick="switchTab('tab-patcher', document.querySelectorAll('.nav-item')[1]); toggleChat(false);">â¨ View in Patcher</button>`;
