    }

    // --- RENAME ---
    let currentRenamePath = "";

    function openRenameModal(path) {
        currentRenamePath = path;
        document.getElementById('rn-old-path-display').innerText = path;
        document.getElementById('rn-new-path').value = path;
        document.getElementById('rename-overlay').classList.add('active');
        document.getElementById('rn-warning').style.display = 'block';
        toggleFab(false);
    }

    function closeRenameModal() {
        document.getElementById('rename-overlay').classList.remove('active');
        toggleFab(true);
    }

    async function executeRename() {
        const newPath = document.getElementById('rn-new-path').value.trim();
        const moveFolder = document.getElementById('rn-move-folder').checked;

        if (!newPath || newPath === currentRenamePath) return closeRenameModal();
        if (isPerformingAction) return;
        isPerformingAction = true;

        const getDir = (p) => p.substring(0, p.lastIndexOf('/') + 1);
        const oldDir = getDir(currentRenamePath);
        const newDir = getDir(newPath);

        showGlobalToast(moveFolder ? "Analyzing folder structure..." : "Preparing move...");

        try {
            let ops = [{ "action": "comment", "text": moveFolder ? `[Bulk Move] ${oldDir} -> ${newDir}` : `[Rename] ${currentRenamePath} -> ${newPath}` }];
            let filesToProcess = [];

            if (moveFolder && oldDir) {
                // Find all siblings
                filesToProcess = window.repoFiles.filter(f => f.path.startsWith(oldDir)).map(f => f.path);
            } else {
                filesToProcess = [currentRenamePath];
            }

            // Concurrent Content Fetching
            const BATCH_SIZE = 5;
            for (let i = 0; i < filesToProcess.length; i += BATCH_SIZE) {
                const batch = filesToProcess.slice(i, i + BATCH_SIZE);
                const batchResults = await Promise.all(batch.map(async (path) => {
                    const res = await fetch(CONFIG.funcUrl, {
                        method: 'POST', headers: {'Content-Type': 'application/json'},
                        body: apiBody({ action: 'preview_file', file_path: path })
                    });
                    const data = await res.json();
                    return { path, content: b64DecodeUnicode(data.content || "") };
                }));

                batchResults.forEach(res => {
                    const targetPath = moveFolder ? res.path.replace(oldDir, newDir) : newPath;
                    ops.push({ "action": "delete_file", "file_path": res.path });
                    ops.push({ "action": "create_file", "file_path": targetPath, "content": res.content });
                });
            }

            closeRenameModal();

            // 2. Load into Patcher
            document.getElementById('json-input').value = JSON.stringify(ops, null, 2);
            saveState();

            // 3. Switch to Patcher
            switchTab('tab-patcher', document.querySelectorAll('.nav-item')[1]);

            showGlobalToast("Rename loaded. Review and Test Patch.");

            // 4. Prompt for AI Healing
            setTimeout(() => {
                if (confirm("File moved! Shall I ask AI to scan and heal imports in other files?")) {
                    startNewChat();
                    toggleChat(true);
                    chatHistory.push({ 
                        role: 'user', 
                        text: `I just renamed "${currentRenamePath}" to "${newPath}". Please scan my project and provide a JSON patch to update any other files that import this file.` 
                    });
                    processAIResponse();
                }
            }, 1000);

        } catch (e) {
            alert("Move failed: " + e.message);
        } finally {
            isPerformingAction = false;
        }
    }

