    function renderStructuredLogs(rawText) {
        const container = document.getElementById('log-custom-container');
        container.innerHTML = '';
        const lines = rawText.split('\n');

        let currentContent = document.createElement('div');
        container.appendChild(currentContent);

        lines.forEach(line => {
            if (line.includes('##[group]')) {
                const details = document.createElement('details');
                details.className = 'log-step';
                details.open = line.toLowerCase().includes('error');

                const summary = document.createElement('summary');
                summary.innerText = line.split('##[group]')[1];

                const content = document.createElement('div');
                content.className = 'log-content';

                details.appendChild(summary);
                details.appendChild(content);
                container.appendChild(details);
                currentContent = content;
                return;
            }

            const row = document.createElement('div');
            row.className = `log-line ${line.toLowerCase().includes('error') ? 'log-err' : ''}`;
            row.innerText = line.replace(/\x1b\[[0-9;]*m/g, '');
            currentContent.appendChild(row);
        });
    }

    // --- GENERIC UI ---
    function formatBytes(bytes) {
        if (!bytes) return '0 B';
        const k = 1024;
        const sizes = ['B', 'KB', 'MB', 'GB'];
        const i = Math.floor(Math.log(bytes) / Math.log(k));
        return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
    }

    function timeAgo(dateString) {
        const date = new Date(dateString);
        const now = new Date();
        const seconds = Math.floor((now - date) / 1000);
        if (seconds < 10) return 'just now';
        if (seconds < 60) return seconds + 's ago';
        const minutes = Math.floor(seconds / 60);
        if (minutes < 60) return minutes + 'm ago';
        const hours = Math.floor(minutes / 60);
        if (hours < 24) return hours + 'h ago';
        return date.toLocaleDateString();
    }

    function renderFileList(files) {
        const container = document.getElementById('file-list-container');
        // Update chat context bar and master checkbox if files change
        updateChatContextIndicator();
        setTimeout(syncSelectAllState, 50);
        container.innerHTML = '';
        if (!files || files.length === 0) return container.innerHTML = '<div style="padding:20px; text-align:center;">No files found.</div>';

        files.forEach(file => {
            const div = document.createElement('div');
            div.className = 'file-item';

            let fileName = file.path.split('/').pop();
            // Intelligence: If it's an Edge Function entry, show the function name instead of index.ts
            if (file.path.includes('supabase/functions/') && fileName === 'index.ts') {
                const segments = file.path.split('/');
                // Expected path: supabase/functions/{NAME}/index.ts
                if (segments.length >= 2) {
                    const functionName = segments[segments.length - 2];
                    fileName = `Î» ${functionName}`;
                }
            }

            const fileSize = formatBytes(file.size);
            const updated = timeAgo(file.last_updated);

            const isExcluded = file.path.endsWith('index.ts') || file.path.includes('supabase/functions/');
            const checkedAttr = isExcluded ? '' : 'checked';

            div.innerHTML = `
                <div class="v-info" onclick="openFileViewer('${file.path}')" style="cursor:pointer; flex:1; min-width: 0; padding-right: 10px;">
                    <strong style="white-space: nowrap; overflow: hidden; text-overflow: ellipsis; display: block; font-size: 13px;">${fileName}</strong>
