                    <button class="menu-btn" onclick="downloadSingleFile('${file.path}', this)" style="color:var(--text-muted);" title="Download">â¬</button>
                    <button class="menu-btn" onclick="stageDeleteFile('${file.path}')" style="color:var(--danger)">ð</button>
                    <input type="checkbox" class="file-check" value="${file.path}" ${checkedAttr} onchange="updateChatContextIndicator(); syncSelectAllState();" style="accent-color:var(--primary)">
                </div>`;
            container.appendChild(div);
