    async function openFileViewer(path) {
        const viewer = document.getElementById('code-viewer');
        viewer.classList.add('active');
        toggleFab(false);
        document.getElementById('viewer-filename').innerText = "Loading " + path + "...";

        if (!aceEditorInstance) {
            aceEditorInstance = ace.edit("ace-container");
            aceEditorInstance.setTheme("ace/theme/tomorrow_night_bright");
            aceEditorInstance.setOption("showPrintMargin", false);
            aceEditorInstance.setOption("fontSize", "13px");
            aceEditorInstance.setReadOnly(true);
        }

        // Reset Mode & State
        currentViewerPath = path;
        originalViewerContent = "";
        aceEditorInstance.setReadOnly(true);
        document.getElementById('viewer-edit-btn').style.color = '';
        document.getElementById('viewer-edit-btn').innerText = 'â Edit';
        document.getElementById('viewer-save-btn').style.display = 'none';

        // Clear stale content immediately
        aceEditorInstance.setValue("Loading content...", -1);

        try {
            const res = await fetch(CONFIG.funcUrl, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: apiBody({
                    action: 'preview_file',
                    file_path: path
                })
            });
            const data = await res.json();
            document.getElementById('viewer-filename').innerText = path;

            let mode = "ace/mode/text";
            if (path.endsWith('.js')) mode = "ace/mode/javascript";
            else if (path.endsWith('.html')) mode = "ace/mode/html";
            else if (path.endsWith('.css')) mode = "ace/mode/css";

            aceEditorInstance.session.setMode(mode);
            const content = b64DecodeUnicode(data.content);
            originalViewerContent = content;
            aceEditorInstance.setValue(content, -1);

            // Listen for changes to show Save button
            aceEditorInstance.session.on('change', () => {
                const currentContent = aceEditorInstance.getValue();
                const hasChanged = currentContent !== originalViewerContent;
                document.getElementById('viewer-save-btn').style.display = hasChanged ? 'block' : 'none';
            });
        } catch (e) {
            aceEditorInstance.setValue(e.message, -1);
        }
    }

