        if (newContent === originalViewerContent) return;

        const saveBtn = document.getElementById('viewer-save-btn');
        saveBtn.disabled = true;
        saveBtn.innerText = "Saving...";

        const ops = [
            { "action": "comment", "text": `Manual edit: ${currentViewerPath}` },
