    async function openStorageObject(name) {
        const prefix = storageCurrentPath.length > 0 ? storageCurrentPath.join('/') + '/' : '';
        const path = prefix + name;
        const ext = name.split('.').pop().toLowerCase();

        const overlay = document.getElementById('storage-viewer-overlay');
        const title = document.getElementById('st-viewer-title');
        const content = document.getElementById('st-viewer-content');
        const dlBtn = document.getElementById('st-viewer-download');

        title.innerText = name;
        content.innerHTML = '<div style="color:var(--ai-accent); font-size:11px;">Fetching Secure Link...</div>';
        overlay.classList.add('active');

        try {
            const res = await fetch(CONFIG.funcUrl, { method: 'POST', headers: {'Content-Type': 'application/json'}, body: apiBody({ action: 'get_storage_signed_url', bucket: storageCurrentBucket, path }) });
            const data = await res.json();

            if(!data.url) throw new Error("URL missing");

            dlBtn.onclick = async () => {
                const originalText = dlBtn.innerText;
                dlBtn.innerText = 'â³ Fetching...';
                dlBtn.disabled = true;
                try {
                    const res = await fetch(data.url);
                    const blob = await res.blob();
                    const blobUrl = URL.createObjectURL(blob);
                    const a = document.createElement('a');
                    a.href = blobUrl;
                    a.download = name;
                    document.body.appendChild(a);
                    a.click();
                    a.remove();
                    URL.revokeObjectURL(blobUrl);
                } catch (err) {
                    showGlobalToast("Download failed: " + err.message, true);
                } finally {
                    dlBtn.innerText = originalText;
                    dlBtn.disabled = false;
                }
            };

            const imageExts = ['jpg', 'jpeg', 'png', 'gif', 'svg', 'webp'];
            const textExts = ['txt', 'js', 'ts', 'json', 'html', 'css', 'md', 'log'];

            if (imageExts.includes(ext)) {
                content.innerHTML = `<img src="${data.url}" style="max-width:100%; max-height:100%; object-fit:contain;">`;
            } else if (textExts.includes(ext)) {
                const textRes = await fetch(data.url);
                const text = await textRes.text();
                content.innerHTML = `<pre style="padding:20px; color:#ccc; font-size:12px; font-family:'JetBrains Mono'; white-space:pre-wrap; width:100%; align-self:flex-start;">${escapeHtml(text)}</pre>`;
            } else {
                content.innerHTML = `<div style="text-align:center; padding:20px;">
                    <div style="font-size:40px; margin-bottom:10px;">ð</div>
                    <div style="color:#888; font-size:11px;">Preview not supported for .${ext} files.</div>
                </div>`;
            }
        } catch(e) { content.innerHTML = `<div style="color:var(--danger);">${e.message}</div>`; }
    }

