    let pendingImportFiles = [];

    async function handleImportFileSelect(input) {
        const file = input.files[0];
        if (!file) return;

        const toast = document.createElement('div');
        toast.innerText = "Parsing " + file.name + "...";
        toast.style.cssText = "position:fixed; bottom:100px; left:50%; transform:translateX(-50%); background:#333; color:white; padding:10px 20px; border-radius:30px; z-index:9999;";
        document.body.appendChild(toast);

        pendingImportFiles = [];

        try {
            if (file.name.endsWith('.zip')) {
                const zip = await JSZip.loadAsync(file);
                const promises = [];
                zip.forEach((relativePath, zipEntry) => {
                    if (!zipEntry.dir) {
                        promises.push(zipEntry.async("string").then(content => {
                            pendingImportFiles.push({ path: relativePath, content: content });
                        }));
                    }
                });
                await Promise.all(promises);
            } 
            else if (file.name.endsWith('.txt')) {
                const text = await file.text();
                // Parse "FILE: path\nContent" format
                // Split by "\n\nFILE: " to handle multiple files, assuming double newline separator from export
                const chunks = text.split(/\n\nFILE: /g);

                chunks.forEach((chunk, index) => {
                    // Handle first chunk edge case if it starts with "FILE: "
                    let cleanChunk = chunk;
                    if (index === 0 && chunk.startsWith("FILE: ")) cleanChunk = chunk.substring(6);

                    const firstLineEnd = cleanChunk.indexOf('\n');
                    if (firstLineEnd !== -1) {
                        const path = cleanChunk.substring(0, firstLineEnd).trim();
                        const content = cleanChunk.substring(firstLineEnd + 1);
                        if (path) pendingImportFiles.push({ path, content });
                    }
                });
            } 
            else {
                throw new Error("Unsupported file format. Use .zip or .txt exported from Conduit.");
            }

            toast.remove();
            document.getElementById('import-count').innerText = `${pendingImportFiles.length} files extracted.`;
            document.getElementById('import-target-repo').value = CONFIG.repoName;
            document.getElementById('import-target-folder').value = "";
            document.getElementById('import-modal').style.display = 'flex';

        } catch (e) {
            toast.remove();
            alert("Parse Error: " + e.message);
        }

        input.value = ''; // Reset input
    }

    function cancelImport() {
        pendingImportFiles = [];
        document.getElementById('import-modal').style.display = 'none';
    }

    async function executeBatchImport() {
        if (pendingImportFiles.length === 0) return;

        const targetRepo = document.getElementById('import-target-repo').value.trim() || CONFIG.repoName;
        let targetFolder = document.getElementById('import-target-folder').value.trim();
        if (targetFolder && !targetFolder.endsWith('/')) targetFolder += '/';

        // Generate Operations
        const operations = pendingImportFiles.map(f => ({
            action: "create_file",
            file_path: targetFolder + f.path,
            content: f.content
        }));

        // Add Summary Comment
        operations.unshift({
            action: "comment",
            text: `[Import] Batch uploaded ${pendingImportFiles.length} files from dump.`
        });

        // Hide Modal & Switch to Terminal
        document.getElementById('import-modal').style.display = 'none';
        switchTab('tab-patcher', document.querySelectorAll('.nav-item')[1]);

        const termId = addTerminalCard(null, { loading: true });

        try {
            // We manually construct payload to override repo_name if needed
            const payload = {
                action: "patch",
                repo_name: targetRepo,
                project_path: CONFIG.projectPath,
                operations: operations,
                ai_config: window.aiConfig // Maintain AI config context
            };

            const res = await fetch(CONFIG.funcUrl, {
                method: 'POST', 
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify(payload)
            });
            const data = await res.json();

            updateTerminalCard(termId, data, operations, true);

            if(data.success && targetRepo === CONFIG.repoName) {
                setTimeout(() => { fetchState(false, false); fetchFileList(); }, 1500);
            }
        } catch (e) {
            updateTerminalCard(termId, { error: e.message });
        }
    }

    async function copySelectedFiles() {
        const checked = Array.from(document.querySelectorAll('#file-list-container .file-check:checked')).map(c => c.value);
        if (checked.length === 0) return showGlobalToast("No files selected", true);

        if (isPerformingAction) return;
        isPerformingAction = true;

        const btn = document.getElementById('btn-context-copy');
        const originalHtml = btn.innerHTML;
        btn.innerHTML = "â³ Fetching...";

        try {
            const fetchedFiles = [];
            const BATCH_SIZE = 8;

            for (let i = 0; i < checked.length; i += BATCH_SIZE) {
                const batch = checked.slice(i, i + BATCH_SIZE);
                showGlobalToast(`â¡ Copying: ${i + 1}-${Math.min(i + BATCH_SIZE, checked.length)} of ${checked.length}...`);

                const batchResults = await Promise.all(batch.map(async (path) => {
                    const res = await fetch(CONFIG.funcUrl, {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: apiBody({ action: 'preview_file', file_path: path })
                    });
                    const data = await res.json();
                    if (!data.content) return null;
                    return { path, content: b64DecodeUnicode(data.content) };
                }));

                fetchedFiles.push(...batchResults.filter(f => f !== null));
            }

            const text = fetchedFiles.map(f => `FILE: ${f.path}\n${f.content}`).join('\n\n');
            await navigator.clipboard.writeText(text);

            btn.innerHTML = "â Copied!";
            btn.style.color = "var(--prod)";
            btn.style.borderColor = "var(--prod)";
            showGlobalToast(`Successfully copied ${fetchedFiles.length} files`);

            setTimeout(() => {
                btn.innerHTML = originalHtml;
                btn.style.color = "";
                btn.style.borderColor = "";
            }, 2000);

        } catch (e) {
            showGlobalToast("Copy failed: " + e.message, true);
            btn.innerHTML = originalHtml;
        } finally {
            isPerformingAction = false;
        }
    }

    async function processExport(type) {
        const checked = Array.from(document.querySelectorAll('#file-list-container .file-check:checked')).map(c => c.value);
        const statusEl = document.getElementById('export-status');

        if (checked.length === 0) return alert("No files selected.");

        if (exportController) exportController.abort(); 
        exportController = new AbortController();
        const signal = exportController.signal;

        try {
            const fetchedFiles = [];
            const BATCH_SIZE = 8; // Optimal balance for browser concurrency and API stability

            for (let i = 0; i < checked.length; i += BATCH_SIZE) {
                if (signal.aborted) throw new Error("Cancelled by user");

                const batch = checked.slice(i, i + BATCH_SIZE);
                statusEl.innerText = `â¡ Parallel Fetching: ${i + 1}-${Math.min(i + BATCH_SIZE, checked.length)} of ${checked.length}...`;
                statusEl.style.color = "var(--ai-accent)";

                const batchResults = await Promise.all(batch.map(async (path) => {
                    const res = await fetch(CONFIG.funcUrl, {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: apiBody({ action: 'preview_file', file_path: path }),
                        signal: signal 
                    });
                    const data = await res.json();
                    if (!data.content) return null;
                    return { path, content: b64DecodeUnicode(data.content) };
                }));

                fetchedFiles.push(...batchResults.filter(f => f !== null));
            }

            statusEl.innerText = "ð¦ Finalizing Bundle...";

            const ts = new Date().toLocaleTimeString('en-GB').replace(/:/g, '');
            const finalBaseName = `${CONFIG.repoName}_${ts}`;

            if (type === 'zip') {
                const zip = new JSZip();
                fetchedFiles.forEach(f => zip.file(f.path, f.content));
                const blob = await zip.generateAsync({ type: "blob" });
                const link = document.createElement('a');
                link.href = URL.createObjectURL(blob);
                link.download = `${finalBaseName}.zip`;
                link.click();
            } else {
                const text = fetchedFiles.map(f => `FILE: ${f.path}\n${f.content}`).join('\n\n');
                const link = document.createElement('a');
                link.href = URL.createObjectURL(new Blob([text], { type: "text/plain" }));
                link.download = `${finalBaseName}.txt`;
                link.click();
            }

            if (!signal.aborted) {
                document.getElementById('export-modal').style.display = 'none';
            }
        } catch (e) {
            if (e.message === "Cancelled by user" || e.name === 'AbortError') {
                statusEl.innerText = "Cancelled.";
                statusEl.style.color = "var(--text-muted)";
            } else {
                statusEl.innerText = "Error: " + e.message;
                statusEl.style.color = "var(--danger)";
            }
        } finally {
            exportController = null;
        }
    }

