    async function deleteSelectedHistory() {
        const checkboxes = Array.from(document.querySelectorAll('.history-check:checked'));
        if (!checkboxes.length) return;

        const idsToDelete = checkboxes.map(cb => cb.value);

        // Find the oldest record among the selection to determine rollback target
        // dbHistory is sorted newest -> oldest
        let oldestSelectedIndex = -1;
        checkboxes.forEach(cb => {
            const idx = dbHistory.findIndex(h => String(h.id) === String(cb.value));
            if (idx > oldestSelectedIndex) oldestSelectedIndex = idx;
        });

        // The target is the first record older than our selection that isn't also being deleted
        let rollbackTarget = null;
        for (let i = oldestSelectedIndex + 1; i < dbHistory.length; i++) {
            if (!idsToDelete.includes(String(dbHistory[i].id))) {
                rollbackTarget = dbHistory[i];
                break;
            }
        }

        let msg = `Delete ${checkboxes.length} selected records?`;
        if (rollbackTarget) {
            msg += `\n\nâ ï¸ This will ROLLBACK your GitHub repository to: "${rollbackTarget.title}"`;
        }

        if (!confirm(msg)) return;

        showGlobalToast("Batch Deleting & Rolling back...");

        // 1. Perform Rollback
        if (rollbackTarget) {
            await fetch(CONFIG.funcUrl, {
                method: 'POST', headers: {'Content-Type': 'application/json'},
                body: apiBody({ action: 'rollback', ref_sha: rollbackTarget.sha })
            });
        }

        // 2. Perform Batch Deletion
        await Promise.all(idsToDelete.map(id => 
            fetch(CONFIG.funcUrl, {
                method: 'POST', headers: {'Content-Type': 'application/json'},
                body: apiBody({ action: 'delete_history', id: id })
            })
        ));

        fetchState(true);
        fetchFileList();
        if (rollbackTarget) setTimeout(() => bundleAndPreview(null), 1000);
    }

