    async function fetchEFLogs(isAppend) {
        const name = document.getElementById('ef-name').value.trim();
        const container = document.getElementById('ef-logs-container');
        const footer = document.getElementById('ef-logs-footer');

        if (!isAppend) {
            container.innerHTML = '<div style="text-align:center; padding:40px; color:var(--ai-accent); animation:pulse 1s infinite;">Fetching Live Cloud Logs...</div>';
            efLogNextTimestamp = null;
        }

        try {
            const res = await fetch(CONFIG.funcUrl, {
                method: 'POST', headers: {'Content-Type': 'application/json'},
                body: apiBody({ 
                    action: 'fetch_ef_logs', 
                    function_slug: name, 
                    before: efLogNextTimestamp 
                })
            });
            const data = await res.json();
            console.log("[IDE] VERBOSE DEBUG PACKET:", JSON.stringify(data, null, 2));

            if (data.error) {
                container.innerHTML = `<div style='padding:20px; color:var(--danger)'><b>API ERROR:</b> ${data.error}<br><pre style='font-size:10px'>${JSON.stringify(data.raw, null, 2)}</pre></div>`;
                return;
            }

            if (!isAppend) container.innerHTML = '';

            if (!data.logs || data.logs.length === 0) {
                if (!isAppend) container.innerHTML = '<div style="text-align:center; padding:40px; color:#666;">No logs found for this function.</div>';
                footer.style.display = 'none';
                return;
            }

            data.logs.forEach(log => {
                const row = document.createElement('div');
                const isError = log.level === 'error';
                row.className = 'ins-row';
                row.style.borderLeft = '3px solid ' + (isError ? 'var(--danger)' : 'var(--prod)');

                // Detect and Prettify JSON in logs
                let displayMessage = escapeHtml(log.event_message || '');
                if (log.event_message && (log.event_message.includes('{') || log.event_message.includes('['))) {
                    try {
                        // Check if the message ITSELF is JSON or contains JSON
                        const jsonMatch = log.event_message.match(/\{.*\}|\[.*\]/);
                        if (jsonMatch) {
                            const parsed = JSON.parse(jsonMatch[0]);
                            displayMessage = log.event_message.replace(jsonMatch[0], renderJsonHighlight(parsed));
                        }
                    } catch(e) { /* Fallback to plain text */ }
                }

                // Safe encoding for attributes to prevent SyntaxErrors from newlines/quotes
                const safeLog = btoa(encodeURIComponent(log.event_message || ''));

                row.innerHTML = `
                    <div class="flex-between" style="margin-bottom:6px;">
                        <span style="color:#555; font-size:10px;">${new Date(log.timestamp).toLocaleString()}</span>
                        <div class="flex-gap">
