                            <button class="action-mini-btn" onclick="copyEncodedLog('${safeLog}')">Copy</button>
                        </div>
                    </div>
                    <div style="white-space:pre-wrap; word-break:break-all; color:${isError ? '#ffcdcd' : '#eee'}; line-height:1.4;">${displayMessage}</div>
                `;
                container.appendChild(row);
                efLogNextTimestamp = log.timestamp;
            });

            // Show button as long as we are finding results, hide only when truly exhausted
            footer.style.display = data.logs.length > 0 ? 'block' : 'none';

        } catch(e) {
            const projectRef = CONFIG.funcUrl.split('https://')[1]?.split('.')[0];
            container.innerHTML = `
                <div style="padding:20px; color:var(--danger); font-size:12px;">
                    <b>Log Fetch Failed</b><br>
                    Error: ${e.message}<br><br>
                    <small style="color:#666">
                        Project Ref: ${projectRef}<br>
                        Function: ${name}<br>
                        Token: ${localStorage.getItem('conduit_access_token') ? 'Configured' : 'Missing'}
                    </small>
                </div>`;
        }
    }

