    async function runBatchTest() {
        if (activeKeysToTest.length === 0) return alert("Load some keys first.");
        const btn = document.getElementById('tester-start-batch-btn');

        btn.disabled = true; 
        btn.innerText = "TESTING...";

        const validLabel = document.getElementById('count-valid-keys');
        const exhaustedLabel = document.getElementById('count-exhausted-keys');
        const bannedLabel = document.getElementById('count-banned-keys');

        validLabel.innerText = '0';
        exhaustedLabel.innerText = '0';
        bannedLabel.innerText = '0';

        let validCount = 0, exhaustedCount = 0, bannedCount = 0;

        // Concurrent run
        const promises = activeKeysToTest.map(async (keyData, idx) => {
            const row = document.getElementById('tester-row-' + idx);
            await validateTesterKey(keyData.api_key, row);

            // Re-check the status updated on the object by validateTesterKey
            const s = keyData.last_status;
            const m = (keyData.last_msg || "").toLowerCase();

            if (s == 200) {
                validCount++;
                validLabel.innerText = validCount;
            } else if (s == 429 || s === "RESOURCE_EXHAUSTED") {
                exhaustedCount++;
                exhaustedLabel.innerText = exhaustedCount;
            } else if (s == 403 || s === "PERMISSION_DENIED" || m.includes("not found") || m.includes("revoked")) {
                bannedCount++;
                bannedLabel.innerText = bannedCount;
            }
        });

        await Promise.all(promises);
        btn.disabled = false;
        btn.innerText = "START TEST";
        document.getElementById('tester-batch-actions').classList.remove('hidden');
        showGlobalToast("Batch Test Complete");
    }

    async function validateTesterKey(apiKey, element, isSingle = false) {
        const resultArea = element.querySelector('.result-area');
        const badge = element.querySelector('.status-badge');
        const model = document.getElementById('tester-batch-modelList').value;

        badge.innerText = "PINGING...";
        badge.className = "status-badge px-2 py-1 rounded text-[10px] font-black uppercase tracking-tighter bg-slate-700 text-blue-400";
        if (isSingle) resultArea.innerHTML = '';

        try {
            // Use selected model from the batch dropdown
            const url = 'https://generativelanguage.googleapis.com/v1beta/' + model + ':generateContent?key=' + apiKey;
            const res = await fetch(url, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ contents: [{ parts: [{ text: "Hello, respond with exactly one word: 'OK'." }] }] })
            });
            const data = await res.json();
            const keyObj = activeKeysToTest.find(k => k.api_key === apiKey);

            if (res.ok) {
                badge.innerText = "SUCCESS";
                badge.className = "status-badge px-2 py-1 rounded text-[10px] font-black uppercase tracking-tighter bg-teal-900/40 text-teal-400";
                resultArea.innerHTML = `<p style="color:#10b981; font-size:12px; margin-top:4px;">â Response: ${data.candidates[0].content.parts[0].text.trim()}</p>`;
                if(keyObj) { keyObj.last_status = 200; keyObj.last_msg = "OK"; }
                return true;
            } else {
                const status = data.error?.code || res.status;
                const msg = data.error?.message || "Unknown Error";
                badge.innerText = status;
                badge.className = "status-badge px-2 py-1 rounded text-[10px] font-black uppercase tracking-tighter bg-red-900/40 text-red-400";
                resultArea.innerHTML = `<p style="color:#ef4444; font-size:11px; margin-top:4px; font-family:monospace;">â ${msg}</p>`;
                if(keyObj) { keyObj.last_status = status; keyObj.last_msg = msg; }
                return false;
            }
        } catch (err) {
            badge.innerText = "FAILED";
            resultArea.innerHTML = '<p style="color:#ef4444; font-size:11px; margin-top:4px;">â Network Error</p>';
            return false;
        }
    }

    function copyTesterReport() {
        let report = `KEY TEST AUDIT REPORT\nGenerated: ${new Date().toLocaleString()}\n${'='.repeat(30)}\n\n`;
        activeKeysToTest.forEach(k => {
            // Export full keys for administrative use
            report += `Name: ${k.name || 'Unnamed'}\nKey: ${k.api_key}\nStatus: ${k.last_status || 'NOT TESTED'}\nMessage: ${k.last_msg || 'N/A'}\n${'-'.repeat(20)}\n`;
        });
        navigator.clipboard.writeText(report).then(() => showGlobalToast("Full audit report copied!"));
    }

    function transitionToSql(sql) {
        closeKeyManager();
        setTimeout(() => {
            openSQLExecutor();
            const editor = document.getElementById('sqlEditor');
            editor.value = sql;
            editor.focus();
            saveSqlState();
            showGlobalToast("SQL Generator: Script Prepared");
        }, 400);
    }

    function cooldownRateLimitedKeys() {
        const limited = activeKeysToTest.filter(k => k.last_status == 429 || k.last_status === "RESOURCE_EXHAUSTED");
        if (limited.length === 0) return showGlobalToast("No rate-limited keys found", true);

        const keys = limited.map(k => `'${k.api_key}'`).join(', ');
        const sql = `-- AUTO-COOLDOWN: Generated by Key Tester\n-- Targeting ${limited.length} keys that hit rate limits\nUPDATE public.api_keys \nSET cooldown_until = NOW() + INTERVAL '1 hour',\n    is_active = true\nWHERE api_key IN (${keys});`;

        transitionToSql(sql);
    }

    function removeBannedKeys() {
        const banned = activeKeysToTest.filter(k => k.last_status == 403 || k.last_status === "PERMISSION_DENIED" || (k.last_msg && k.last_msg.toLowerCase().includes("api key not found")));
        if (banned.length === 0) return showGlobalToast("No banned keys found", true);

        const keys = banned.map(k => `'${k.api_key}'`).join(', ');
        const sql = `-- REAPER: Generated by Key Tester\n-- Deleting ${banned.length} keys that are revoked/banned\nDELETE FROM public.api_keys \nWHERE api_key IN (${keys});`;

        transitionToSql(sql);
    }

    function downloadSqlCsv() {
        if (!lastSqlResultData || lastSqlResultData.isError) return;
        const csvContent = convertToCSV(lastSqlResultData);
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');

        const tables = extractTableNames(lastSqlResultData.sql);
        const tableSlug = tables.length > 0 ? tables.join('_').substring(0, 30) + '_' : '';
        const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 10);

        link.setAttribute('href', url);
        link.setAttribute('download', `${tableSlug}export_${timestamp}.csv`);
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        showGlobalToast('CSV Download Started');
    }
